/**
 * interleaver.c — OFDM bit interleaver (legacy and HT)
 *
 * Legacy: IEEE 802.11-2020 Equation 17-17, N_col=16.
 * HT: Section 19.3.11.8.2, N_col=13, N_row=4*N_bpsc.
 *
 * Deinterleave uses pre-computed permutation tables for all valid
 * (n_cbps, n_bpsc) combinations. This eliminates expensive per-call
 * integer division/modulo on ARM (Cortex-A9 has no hardware divider).
 */

#include "lib80211/interleaver.h"
#include <string.h>

/* Maximum n_cbps: 288 (64QAM legacy) or 416 (256QAM VHT) */
#define MAX_CBPS 416

/* ========================================================================
 * Forward interleaver (TX path — computed per call, not hot path)
 * ======================================================================== */

static void interleave_generic(const uint8_t *in_bits, uint8_t *out_bits,
                               int n_cbps, int n_bpsc, int n_col) {
    int n_row = n_cbps / n_col;
    int s = (n_bpsc / 2);
    if (s < 1) s = 1;

    for (int k = 0; k < n_cbps; k++) {
        int i = n_row * (k % n_col) + (k / n_col);
        int j = s * (i / s) + (i + n_cbps - (n_col * i / n_cbps)) % s;
        out_bits[j] = in_bits[k];
    }
}

void lib80211_interleave(const uint8_t *in_bits, uint8_t *out_bits,
                         int n_cbps, int n_bpsc) {
    interleave_generic(in_bits, out_bits, n_cbps, n_bpsc, 16);
}

void lib80211_interleave_ht(const uint8_t *in_bits, uint8_t *out_bits,
                            int n_cbps, int n_bpsc) {
    interleave_generic(in_bits, out_bits, n_cbps, n_bpsc, 13);
}

/* ========================================================================
 * Pre-computed deinterleave permutation tables
 *
 * perm[k] = interleaved position that maps to deinterleaved position k.
 * Usage: out[k] = in[perm[k]]
 *
 * Legacy (N_col=16): 4 tables for n_cbps ∈ {48, 96, 192, 288}
 * HT/VHT (N_col=13): 5 tables for n_cbps ∈ {52, 104, 208, 312, 416}
 * ======================================================================== */

