/* ========================================================================
 * Deinterleave dispatch — select pre-computed table, apply gather
 * ======================================================================== */

static const uint16_t *get_deintlv_table_legacy(int n_cbps) {
    switch (n_cbps) {
        case  48: return deintlv_leg_48;
        case  96: return deintlv_leg_96;
        case 192: return deintlv_leg_192;
        case 288: return deintlv_leg_288;
        default:  return NULL;
    }
}

static const uint16_t *get_deintlv_table_ht(int n_cbps) {
    switch (n_cbps) {
        case  52: return deintlv_ht_52;
        case 104: return deintlv_ht_104;
        case 208: return deintlv_ht_208;
        case 312: return deintlv_ht_312;
        case 416: return deintlv_ht_416;
        default:  return NULL;
    }
}

/**
 * Apply deinterleave using pre-computed permutation table.
 * out[k] = in[perm[k]] for k=0..n_cbps-1.
 */
static void deinterleave_table(const float *in_soft, float *out_soft,
                               const uint16_t *perm, int n_cbps) {
    for (int k = 0; k < n_cbps; k++) {
        out_soft[k] = in_soft[perm[k]];
    }
}

/**
 * Fallback: compute permutation at runtime (for unexpected parameters).
 */
static void deinterleave_generic(const float *in_soft, float *out_soft,
                                 int n_cbps, int n_bpsc, int n_col) {
    int perm[MAX_CBPS];
    int n_row = n_cbps / n_col;
    int s = (n_bpsc / 2);
    if (s < 1) s = 1;

    for (int k = 0; k < n_cbps; k++) {
        int i = n_row * (k % n_col) + (k / n_col);
        int j = s * (i / s) + (i + n_cbps - (n_col * i / n_cbps)) % s;
        perm[k] = j;
    }

    for (int k = 0; k < n_cbps; k++) {
        out_soft[k] = in_soft[perm[k]];
    }
}

void lib80211_deinterleave(const float *in_soft, float *out_soft,
                           int n_cbps, int n_bpsc) {
    const uint16_t *tbl = get_deintlv_table_legacy(n_cbps);
    if (tbl) {
        deinterleave_table(in_soft, out_soft, tbl, n_cbps);
    } else {
        deinterleave_generic(in_soft, out_soft, n_cbps, n_bpsc, 16);
    }
}

void lib80211_deinterleave_ht(const float *in_soft, float *out_soft,
                              int n_cbps, int n_bpsc) {
    const uint16_t *tbl = get_deintlv_table_ht(n_cbps);
    if (tbl) {
        deinterleave_table(in_soft, out_soft, tbl, n_cbps);
    } else {
        deinterleave_generic(in_soft, out_soft, n_cbps, n_bpsc, 13);
    }
}
